INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('1001','Internal.wecom_group_message','{"key": "Internal.wecom_group_message", "title": "企业微信群消息", "version": "1.0.0", "src": "astronverse.internal.internal.Internal().wecom_group_message", "comment": "向机器人地址(@{robot_url})发送文本(@{content})，@某人手机号(@{mentioned_mobile})，响应保存至(@{response_text})", "inputList": [{"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "robot_url", "title": "机器人地址", "name": "robot_url", "tip": "企业微信群机器人的 Webhook 地址", "default": "", "value": [{"type": "str", "value": ""}], "required": true}, {"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "content", "title": "文本内容", "name": "content", "tip": "消息正文", "default": "", "value": [{"type": "str", "value": ""}], "required": true}, {"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "mentioned_mobile", "title": "@某人（手机号）", "name": "mentioned_mobile", "tip": "需要 @ 的用户手机号，多个用英文逗号分隔，如 15563371738,13800138000", "default": "", "value": [{"type": "str", "value": ""}], "required": false}], "outputList": [{"types": "Str", "formType": {"type": "RESULT"}, "key": "response_text", "title": "响应内容", "tip": "接口返回的文本结果"}], "icon": "wecom-robot-message", "helpManual": "向企业微信群机器人 Webhook 发送 text 消息；多个手机号用英文逗号分隔。"}',NULL,'2026-04-15 12:00:00','2026-04-15 12:00:00');
INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('1002','Internal.yunshang_lunan_message','{"key": "Internal.yunshang_lunan_message", "title": "云上鲁南消息推送", "version": "1.0.0", "src": "astronverse.internal.internal.Internal().yunshang_lunan_message", "comment": "由服务端转发至云上鲁南接口，接收方(@{receiver_id})，类型(@{msg_type})，响应保存至(@{response_text})", "inputList": [{"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "receiver_id", "title": "接收方工号", "name": "receiver_id", "tip": "receiver_id，接收方工号", "default": "", "value": [{"type": "str", "value": ""}], "required": true}, {"types": "YunshangLunanMsgType", "formType": {"type": "RADIO"}, "key": "msg_type", "title": "消息类型", "name": "msg_type", "tip": "Text 为文本消息需填写正文；File 为文件消息需填写链接并在 text 中传文件信息 JSON", "options": [{"label": "Text（文本）", "value": "Text"}, {"label": "File（文件）", "value": "File"}], "default": "Text", "required": true}, {"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "text", "title": "消息内容", "name": "text", "tip": "Text 时填写正文；File 时填写 {\"fileName\":\"file_name\",\"fileSize\":\"file_size\"}", "default": "", "value": [{"type": "str", "value": ""}], "dynamics": [{"key": "$this.text.show", "expression": "return $this.msg_type.value == ''Text''"}], "required": false}, {"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "link", "title": "附件链接", "name": "link", "tip": "msg_type 为 File 时填写", "default": "", "value": [{"type": "str", "value": ""}], "dynamics": [{"key": "$this.link.show", "expression": "return $this.msg_type.value == ''File''"}], "required": false}, {"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "file_name", "title": "文件名", "name": "file_name", "tip": "msg_type 为 File 时填写，系统会封装进 text 的 fileName", "default": "", "value": [{"type": "str", "value": ""}], "dynamics": [{"key": "$this.file_name.show", "expression": "return $this.msg_type.value == ''File''"}], "required": false}, {"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "file_size", "title": "文件大小", "name": "file_size", "tip": "msg_type 为 File 时填写，系统会封装进 text 的 fileSize", "default": "", "value": [{"type": "str", "value": ""}], "dynamics": [{"key": "$this.file_size.show", "expression": "return $this.msg_type.value == ''File''"}], "required": false}], "outputList": [{"types": "Str", "formType": {"type": "RESULT"}, "key": "response_text", "title": "响应内容", "tip": "接口返回的文本结果"}], "icon": "cloud-lunan-message", "helpManual": "接口地址、token、AES 密钥、签名等在后端环境变量配置；Text 消息填写正文；File 消息填写链接、文件名、文件大小，系统会将文件信息封装到 text 字段。"}',NULL,'2026-04-15 12:00:00','2026-04-15 12:00:00');
